import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class InputHandlerServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        out.println("User input: " + encodeHtml(userInput)); // Displaying properly encoded user input on the webpage
    }

    private String encodeHtml(String input) {
        if (input == null) {
            return "";
        }

        StringBuilder encoded = new StringBuilder();

        for (char c : input.toCharArray()) {
            switch (c) {
                case '<':
                    encoded.append("&lt;");
                    break;
                case '>':
                    encoded.append("&gt;");
                    break;
                case '&':
                    encoded.append("&amp;");
                    break;
                case '"':
                    encoded.append("&quot;");
                    break;
                default:
                    encoded.append(c);
            }
        }

        return encoded.toString();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
